// Track: Portuguese (Brazil), for an English speaker. Deepened 2026-07-10
// (#38 pass, parity standard): all six CEFR tiers ≥3 items, promptNative
// subtitles throughout, first C1/C2 content — including Portuguese's two
// flagship grammar features (the future subjunctive and the personal
// infinitive), saudade/cafuné/gambiarra as cultural vocabulary, and the
// carioca-to-general R-as-H, ão nasals, and cê/pra reductions in phonetics.
// Also fixed a pre-existing bug: the pão-plural item listed "pães" twice.
// ⚠️ PENDING #41: no confirmed Brazilian reviewer — queue via 41b channels. Categories: vocab (basics + Brazil-specific vocabulary,
// distinct from European Portuguese), gram (gerund preference, você vs. tu,
// object pronoun placement — genuine differences from European Portuguese,
// plus core Portuguese grammar), trad (idioms), and fono (nasal vowels,
// d/t palatalization before i — the things that actually trip up English
// speakers reading Brazilian Portuguese aloud).

import { buildFrequencyBank } from "../../lib/frequencyVocab";
import WORDS from "../vocab/ptBrWords";

const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);

// Word Bank prompt formulas for buildFrequencyBank (generator is language-neutral).
const PT_FORMULAS = {
  recognitionPrompt: (w) => `'${cap(w)}' significa...`,
  recognitionNative: (w) => ({ en: `'${cap(w)}' means...` }),
  recognitionExplain: (w, g, noteEn) => ({
    en: `'${cap(w)}' means ${g}.${noteEn}`,
    es: `'${cap(w)}' significa ${g}.`,
  }),
  productionPrompt: (g) => `Como se diz '${g}' em português?`,
  productionNative: (g) => ({ en: `How do you say '${g}' in Portuguese?` }),
  productionExplain: (w, g, noteEn) => ({
    en: `'${g}' is '${w}'.${noteEn}`,
    es: `'${g}' se dice '${w}'.`,
  }),
};

import { THEMES, tagFor } from "./ptBrForEnTags";

